var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"고생하셨습니다, 그레이스 님. 이번 무구의 선별은 평소보다 순조로우셨나 보군요.","JPN":"お疲れ様でした、グレース様。今回の武具の選別はいつもより順調だったようですね。","ENG":"Welcome back, Dame Grace. It seems the selection of your Armament went more smoothly than usual this time.","TWN":"辛苦了，葛瑞絲小姐。這次武器的挑選似乎比平時順利呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 물병자리의 가호를 받은 대로 물처럼 맑은 여식이었습니다.","JPN":"ええ。水瓶座の加護を受けるにふさわしい、水のように澄んだ娘でした。","ENG":"Indeed. As if blessed by Aquarius, the young lady I met was as clear and calm as water.","TWN":"是的。她是受到水瓶座守護的，如水般清澈的女孩。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예정보다 이른 시간에 복귀한 탓에, 루지에가 불만이 많아보였지만요.","JPN":"予定より早く復帰したので、ルージは不満そうでしたが。","ENG":"I returned earlier than planned, so Rougié looked quite displeased.","TWN":"由於比預定時間提前返回，路吉爾似乎有很多不滿。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"이번에도 단원들에게 당부 없이 돌아오신 겁니까?","JPN":"また団員たちに事前告知もなくお戻りになったのですか？","ENG":"You left without saying a word to your knights again, didn't you?","TWN":"這次也是沒有通知團員就回來了吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"깜짝 놀라게 할 생각이었는지라.","JPN":"びっくりさせたいと思いましたので。","ENG":"Well, I did want to surprise them.","TWN":"本來就是想嚇你一跳的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"……확실히 놀랐겠군요, 그건.","JPN":"……それは確かにびっくりしますね。","ENG":"...Yes, I'm sure they were very surprised.","TWN":"……確實讓人吃驚。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"받으시죠. 노인의 얕은 식견으로 우려낸 차입니다.","JPN":"どうぞ。年寄りの浅知恵で淹れたお茶です。","ENG":"Here. A simple brew from an old man's shallow wisdom.","TWN":"請享用。這是我剛才泡好的茶。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아… 감사합니다.","JPN":"あ……ありがとうございます。","ENG":"Ah... thank you.","TWN":"啊……謝謝你。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"별말씀을요. 변변찮은 다과도 차려드리지 못해 죄송할 따름입니다.","JPN":"どういたしまして。茶菓子もお出しできず、申し訳ないかぎりです。","ENG":"Think nothing of it. I only regret I couldn't offer you a proper tea service.","TWN":"哪裡的話，我只是遺憾沒能為你準備好茶點。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BUTLER_PRIDE_NULL_NULL","text":{"KOREA":"늙은이는 이만 자리를 비울 테니, 그레이스 님과 느긋하게 이야기 나누시길.","JPN":"老体はこれで失礼いたしますので、グレース様とごゆっくりお話しください。","ENG":"I'll take my leave now. Please enjoy a relaxed conversation with Dame Grace.","TWN":"那我就先告退，你可以和葛瑞絲小姐慢慢聊聊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"목을 축일 차도 준비되었으니 이야기를 계속해보지요.","JPN":"喉を潤すお茶も来たことですし、お話を続けましょうか。","ENG":"Now that we've something to soothe the throat, shall we continue?","TWN":"準備好潤喉的茶了，我們繼續聊吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"혹, 제게 궁금한 게 있으신지요?","JPN":"私について聞きたいことはありますか？","ENG":"Is there anything else you wish to ask me?","TWN":"請問，你對我有什麼好奇的嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……앞서 만난 기사가 당신을 버밍엄 가문의 후계자라 말하더군요.","JPN":"……さっき会った騎士が、あなたをバーミンガム家の後継者と言っていました。","ENG":"...A knight I met earlier said you were heir to House Birmingham.","TWN":"……之前遇到的騎士說你是伯明罕家族的繼承人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무언가 문제라도?","JPN":"何か問題でも？","ENG":"Is there a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"많습니다! 알렌 경은 가문의 후계자인 아내 분과 오래 전에 사별하셨다 말했어요!","JPN":"大ありです！　アレン卿から一族の後継者である夫人とはずいぶん前に死別されたと聞きました！","ENG":"A lot! Sir Allen said the heir of that house passed away years ago!","TWN":"很多！艾倫卿說他很久以前就和家族繼承人的妻子分開了！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"애당초, 버밍엄 가문은 이미 멸족한 가문입니다!","JPN":"そもそも、バーミンガム家はすでに滅亡しています！","ENG":"The Birmingham line was declared extinct!","TWN":"本來，伯明罕家族已經滅族了！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 그리 매섭게 노려보지 마시지요. 구태여 꺼낸 답변을 채 잇기가 두렵습니다.","JPN":"ふふ。そんなに恐い顔で睨まないでください。やっとのことで用意した答えをお話しすることが怖くなります。","ENG":"My, such a fierce glare. It almost makes me afraid to finish what I was about to say.","TWN":"呵呵。別那麼兇狠地盯著我嘛。我還怕接不上你特意提出來的回答呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경의 추측대로 저는 그레이스 버밍엄이 아닙니다.","JPN":"卿の推測どおり、私はグレース・バーミンガムではありません。","ENG":"As you suspect, I am not Grace Birmingham.","TWN":"正如你所猜測的，我不是葛瑞絲·伯明罕。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나, 동시에 그레이스 버밍엄이기도 하지요.","JPN":"ですが、それと同時にグレース・バーミンガムでもあります。","ENG":"And yet, I am also Grace Birmingham.","TWN":"不過，同時我也是葛瑞絲·伯明罕。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금 저를 놀리시는 겁니까?","JPN":"からかっているのですか？","ENG":"Are you mocking me right now?","TWN":"現在是在耍我嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"섭섭한 말씀을 하시네요. 귀족이라는 작자가 어찌 이런 일에 장난을 치겠습니까?","JPN":"とんでもありません。貴族たるもの、このような場面で冗談など言いません。","ENG":"How disappointing. What sort of noble would joke about something so serious?","TWN":"你這話讓我感到遺憾。身為貴族的人怎麼會在這種事情上開玩笑呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그저 직접적인 사실을 밝힐 수 없을 뿐입니다.","JPN":"ただ、事実そのものを明かすことができないだけです。","ENG":"I simply cannot reveal the full truth so directly.","TWN":"只是無法直接揭露事實而已。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여기서 제가 진실을 고한 들, 경께서 원하시는 진실에 다다를 순 없을 테니까요.","JPN":"それに、ここで私が真実を告げようとも、求めている真実にたどり着くことはできないでしょう。","ENG":"Even if I told you everything now, it wouldn't be the truth you seek.","TWN":"即使我在這裡說出真相，也無法達到你所期望的真相。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……아무래도, 제대로 답해주실 생각은 없어 보이는군요.","JPN":"……どうやら、ちゃんと答えてくれる気はなさそうですね。","ENG":"...So you have no intention of giving me a real answer.","TWN":"……看來，你並不打算好好回答我的問題。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"신경 써주셔서 감사합니다만, 이만 돌아가겠습니다.","JPN":"お気遣いありがとうございます。ですが、もう帰ります。","ENG":"Thank you for your concern, but I'll be taking my leave.","TWN":"多謝關照，不過我該回去了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이르네요. 아직 호위에 대한 보답도 돌려드리지 못했는데.","JPN":"もうですか。まだ護衛のお礼もしておりません。","ENG":"So soon? I haven't even repaid you for your escort.","TWN":"太早了。我還沒能回報你的護衛之恩呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"대신이라고 하긴 뭐합니다만.","JPN":"代わりといっては何ですが。","ENG":"This isn't much, but consider it a parting gift.","TWN":"雖然說是代替品，但也不太合適。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"This is...?","TWN":"這是？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제국의 지도입니다. 얼마 안 가 돌아오실 텐데, 백작가의 위치 정도는 알아두셔야지요.","JPN":"帝国の地図です。もうすぐお帰りになるのに、伯爵家の位置程度は知っておく必要があると思いまして。","ENG":"A map of the Empire. You'll be returning soon enough, so it's best to know where the County estate lies.","TWN":"這是帝國的地圖。你很快就會回來，至少應該知道伯爵家的位置。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"원하시면 수행인을 동행시켜드리겠습니다만, 어쩌시겠습니까?","JPN":"お望みなら付き人を手配しますが、いかがなさいますか？","ENG":"If you wish, I can assign someone to accompany you. What will it be?","TWN":"如果你需要，我可以為你安排隨從，你覺得怎麼樣？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"신세 졌습니다. 이만 가보도록 하죠.","JPN":"お世話になりました。これで失礼いたします。","ENG":"I'm grateful. I'll be off, then.","TWN":"多謝關照了。我就先走了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오랜만이네요, 에스텔. 정확하게 18시간 만이에요.","JPN":"久しぶりです、エステル。正確には18時間ぶりですね。","ENG":"It's been a while, Esther. Precisely eighteen hours, in fact.","TWN":"好久不見，艾斯特。準確來說是18小時沒見了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제도의 풍경은 마음껏 즐기셨는지요?","JPN":"帝都の風景は満喫されましたか。","ENG":"Did you enjoy the sights of the capital?","TWN":"你是否盡情享受了首都的風景？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"주변 지형이 생소한 것을 넘어 통화나 기본적인 상식조차 다르더군요.","JPN":"周りの地形もそうですが、通貨や基本的な常識さえ違っていました。","ENG":"The geography was unfamiliar, but even the currency and basic knowledge seemed foreign.","TWN":"周圍的地形不僅陌生，連說話方式和基本常識都不一樣呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"네. 센트럴 팰리스니까요.","JPN":"ええ。セントラルパレスですから。","ENG":"That's to be expected. This is Central Palace, after all.","TWN":"是的。因為這裡是聖特羅貝里斯。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그런 지명은 들어보지 못했습니다.","JPN":"その地名を聞いたのは初めてです。","ENG":"I've never heard of such a place.","TWN":"我沒聽說過那個地名。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"옛 문헌에도 나오지 않는 문명을 어찌 들어 보셨겠습니까?","JPN":"昔の文献にも出ていない文明ですから、知っている方がおかしいというものです。","ENG":"Why would you have? It's a civilization not recorded in any old text.","TWN":"古籍中都沒有記載的文明，你怎麼會聽說過呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"미몽에 홀려 간밤에 꾸는 꿈을 현실과 착란하시면 곤란합니다.","JPN":"夢まぼろしの世界と現実を勘違いしてはいけません。","ENG":"It's troubling when dreams blur into reality just because they feel vivid.","TWN":"被虛幻迷惑，若將昨夜的夢境與現實混淆可就麻煩了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"버고 소드를 뽑은 이래, 이런 경험은 숱하게 하셨을 텐데요?","JPN":"ヴァルゴソードを抜いて以来、こういう経験を何度もしたはずです。","ENG":"You've drawn the Virgo Sword, haven't you? You must be used to strange experiences by now.","TWN":"拔出布林加夫之劍後，你應該經歷過很多這樣的事情吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"꿈이라고 하기엔 제 의식은 너무나도 또렷하군요.","JPN":"夢と呼ぶには、あまりにも意識がはっきりとしています。","ENG":"If this is a dream, my senses are far too clear.","TWN":"說是夢吧，但我的意識卻異常清晰。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면 이건, 필히 자각몽이겠군요.","JPN":"でしたらそれは、きっと明晰夢でしょう。","ENG":"Then it must be a lucid dream.","TWN":"那麼這一定是清醒夢了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"클리포트 게임 경과 보고서에서 본 기억이 있습니다.","JPN":"クリフォトゲーム経過報告書で読んだ覚えがあります。","ENG":"I recall something similar from the Qliphoth Game report.","TWN":"我記得在逆卡巴拉遊戲的進度報告中見過。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당시 현장에서는 마왕의 능력으로 과거의 환각을 본 이들이 있었다더군요.","JPN":"当時、現場には魔王の能力で過去の幻覚を見た人々がいたそうです。","ENG":"Some at the scene saw illusions of the past due to the Demon Lord's powers.","TWN":"當時在現場，有人因為魔王的能力看到了過去的幻覺。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인께서는 구원기사단… 마왕의 사도인 겁니까?","JPN":"夫人は救世騎士団……魔王の使徒なのですか？","ENG":"Are you one of the Apostles... from the Knights of Redemption?","TWN":"夫人是救贖騎士團……魔王的使徒嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"마왕이 죽었는데 어찌 사도가 살아남을 수 있겠습니까?","JPN":"魔王が死んだのに、使徒が生き残るわけがありません。","ENG":"The Demon Lord is dead. How could an Apostle still remain?","TWN":"魔王已死，怎能讓使徒活下來呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"만약 그렇다면 전제가 잘못되었거나, 혹 다른 힘이 영향을 미치고 있는 것이겠지요.","JPN":"もしそうだとしたら前提が間違っているか、別の力が影響しているのでしょう。","ENG":"If that were true, then something in your premise must be off, or another force is at play.","TWN":"如果是這樣的話，可能是假設有誤，或者是其他力量在影響著吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……사도가 아닐지 언정, 그림자가 아공간을 다루는 모습은 이미 본 적이 있습니다.","JPN":"……使徒でないとしても、シャドウが亜空間を扱うところを目撃しました。","ENG":"...Even if you're not an Apostle, I've seen a Shadow manipulate a dimensional pocket.","TWN":"……雖然不是使徒，但我們已經見過暗影操控亞空間的樣子了。"},"stage":{"bg":"MS_1106","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"현실과 동떨어진 이곳이 진짜 현실일 거라는 생각은 들지 않는군요.","JPN":"現実とかけ離れたここが、本当の現実とは思えません。","ENG":"This place doesn't feel like the real world.","TWN":"我不覺得這個與現實脫節的地方會是真正的現實。"},"stage":{"bg":"MS_1106","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"MS_1106","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"훌륭합니다. 사고가 제한될 법한 상황임에도 용케 결론에 다다르셨군요.","JPN":"お見事です。思考が制限される状況下でよく結論にたどり着きましたね。","ENG":"Impressive. Even with your thinking constrained, you managed to reach a conclusion.","TWN":"太棒了。在這種可能限制思考的情況下，你竟然能得出結論。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"말씀하신 것의 절반은 맞습니다. 이곳은 필히 제 존재가 얽혀있는 공간이지요.","JPN":"おっしゃったことの半分は正解です。ここはきっと私という存在が捕らえられている空間なのです。","ENG":"You're half correct. This place is indeed tied to my existence.","TWN":"你說的有一半是對的。這裡確實是與我的存在緊密相連的空間。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그렇다면 절 이곳에 가둔 이유는 무엇입니까?","JPN":"それなら、私をここに閉じ込めた理由はなんですか？","ENG":"Then why capture me here? What was your purpose?","TWN":"那麼，把我困在這裡的理由是什麼？"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"가뒀다는 건 어폐가 있군요. 경께서 이곳에 다다르신 건 운명이자, 또한 숙명입니다.","JPN":"閉じ込めたという言葉には語弊があります。卿がここにたどり着いたのは運命であり、宿命でもあります。","ENG":"\\"Capture\\" is not quite right. You arrived here by fate. And by destiny.","TWN":"說是囚禁在這裡有些不妥。你來到這裡是命運，也是宿命。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나… 제게도 분명 사사로운 욕심은 존재하겠지요.","JPN":"ですが……私にも個人的な欲望があるはずです。","ENG":"Still... I won't deny that I have personal motives as well.","TWN":"不過……我也肯定有一些私人的欲望吧。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"수없이 꼬여 있던 매듭이 풀어짐에 하늘의 별들이 본 궤도에 올라가기 시작했습니다.","JPN":"絡まっていた数多の結び目がほどかれ、空の星たちは本来の軌道に戻りつつあります。","ENG":"Now that the many tangled threads have begun to unravel, the stars are falling back into orbit.","TWN":"無數糾纏的結解開後，天空的星星開始回到它們的軌道上。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 궤도에 오르지 못한 별들은 그 빛을 잃어 제 앞길조차 밝히지 못하겠지요.","JPN":"ですが、軌道に戻れなかった星たちはその光を失い、自分の未来すら照らすことは叶わないでしょう。","ENG":"But those that remain out of alignment have lost their light. They can't even illuminate the path ahead.","TWN":"然而，那些未能進入軌道的星星將失去光芒，甚至無法照亮自己的前路。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 경께서 이러한 별들의 이야기를 들어주셨으면 합니다.","JPN":"私は卿にそんな星たちの話を聞いてほしいのです。","ENG":"I want you to listen to the stories of those stars.","TWN":"我希望你能傾聽這些星星的故事。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별의 이야기를… 말입니까?","JPN":"星の話……ですか？","ENG":"Stories of the stars...?","TWN":"你是說……星星的故事嗎？"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"모든 이야기는 의문으로부터 시작되는 법이니 당장 이해하실 필요는 없습니다.","JPN":"すべての話は疑問から始まるものですので、今すぐ理解なさる必要はありません。","ENG":"Every story begins with a question. There's no need to understand right away.","TWN":"所有故事都從疑問開始，所以不必急於理解。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 확실한 건, 경의 추측대로 이곳은 과거의 기억의 재현이며.","JPN":"確かなのは、卿の推測どおり、ここは過去の記憶の再現であり。","ENG":"But you were right. This place is a reconstruction of the past as you speculated.","TWN":"但可以確定的是，如你所料，這裡是過去記憶的重現。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 이야기의 끝에 다다르면 어떤 형태로든 경께서는 진실에 다다르실 겁니다.","JPN":"卿はその話の最後に、どのような形であろうと真実にたどり着くことになるでしょう。","ENG":"And when the story reaches its end, you'll reach the truth in one form or another.","TWN":"當你走到故事的盡頭時，無論以何種形式，你都會接觸到真相。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……말의 진위를 파악할 순 없으나, 마지막으로 부인께 여쭙겠습니다.","JPN":"……言葉の真偽は不明ですが、最後に夫人にお聞きします。","ENG":"...I can't tell if your words are true or false, but let me ask you one last thing.","TWN":"……雖然無法判斷話語的真實性，但最後還是請夫人回答一下。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신은… 대체 누구십니까?","JPN":"あなたは……いったい誰なのですか？","ENG":"Who... are you, really?","TWN":"你……到底是誰？"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당장 대답해드릴 수 있는 건 없습니다.","JPN":"今ここでお答えすることはできません。","ENG":"I can't answer that yet.","TWN":"我現在無法給出答案。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"분명 그 또한, 경께서 찾으셔야 하는 답 중 하나일 테니까요.","JPN":"きっとそれもまた、卿が探さねばならない答えの一つでしょうから。","ENG":"Because finding that answer is part of your journey.","TWN":"因為那也是你需要尋找的答案之一。"},"stage":{"bg":"ROOM_03","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};